; 移動ポイント
(A) = map:モイーズ湿地帯・東の沼地, x:16 ,y:0, way:n, symbol:movev, ask:Go to the next map?
(B) = map:常闇の城１Ｆ, x:10, y:5, way:w, symbol:cave, ask:Go to the dungeon?
(C) = map:モイーズ湿地帯・死者の沼, x:6 ,y:29, way:s, symbol:movev, ask:Go to the next map?
(D) = map:モイーズ湿地帯・死者の沼, x:7 ,y:29, way:s, symbol:movev, ask:Go to the next map?

; 宝箱
box[1] = マジカルボウ_u,タワーシールド,ゴールドトンファー_u,経験のコイン（中）,金貨（大）
box[2] = 悪魔の盾_u,ブラックブーツ_u,復活の粉,金貨（大）

