[elsif exp='isTEO'][テオ f=17]「Damn it! You...!」[k]
[elsif exp='isHUM || isDWA'][キャラ f=17]「Help me!」[k]
[elsif exp='isELF || isSYL'][キャラ f=17]「No! Let go of me!」[k]
